// Read all rows coming from Google Sheets and turn A/B columns into key/value pairs
const items = $input.all();
const pairs = [];
for (const it of items) {
  const r = it.json;
  if (!r || typeof r !== 'object') continue;

  if ('A' in r && 'B' in r) {
    const k = String(r.A ?? '').trim();
    const v = String(r.B ?? '').trim();
    if (k) pairs.push([k, v]);
  } else if (Array.isArray(r.values) && r.values.length >= 2) {
    const k = String(r.values[0] ?? '').trim();
    const v = String(r.values[1] ?? '').trim();
    if (k) pairs.push([k, v]);
  } else {
    // Generic fallback: use first two keys
    const keys = Object.keys(r);
    if (keys.length >= 2) {
      const k = String(r[keys[0]] ?? '').trim();
      const v = String(r[keys[1]] ?? '').trim();
      if (k) pairs.push([k, v]);
    }
  }
}

// ---------- Robust time parser with Sheets/Excel serial support ----------
function hhmmParts(input) {
  if (input == null) return [9, 0];

  let s = String(input).trim().toLowerCase();

  // Numeric paths (numbers, decimals, date serials)
  if (!isNaN(Number(s))) {
    const n = Number(s);
    if (!isFinite(n)) return [9, 0];

    const frac = n - Math.floor(n);

    // Fraction of a day (0..1)
    if (n >= 0 && n < 1) {
      const totalMin = Math.round(n * 24 * 60);
      const h = Math.floor(totalMin / 60) % 24;
      const m = totalMin % 60;
      return [h, m];
    }

    // Date serial with fractional day
    if (frac > 0 && frac < 1) {
      const totalMin = Math.round(frac * 24 * 60);
      const h = Math.floor(totalMin / 60) % 24;
      const m = totalMin % 60;
      return [h, m];
    }

    // Decimal hours (e.g., 9.5 -> 09:30)
    const h = Math.floor(n);
    const m = Math.round((n - h) * 60);
    return [((h % 24) + 24) % 24, Math.max(0, Math.min(59, m))];
  }

  // Remove spaces for AM/PM parsing
  s = s.replace(/\s+/g, '');

  // "9pm", "9:30am"
  const ampm = s.match(/^(\d{1,2})(?::?(\d{2}))?(am|pm)$/i);
  if (ampm) {
    let h = parseInt(ampm[1], 10);
    const m = parseInt(ampm[2] ?? '0', 10);
    const mer = ampm[3];
    if (mer === 'pm' && h < 12) h += 12;
    if (mer === 'am' && h === 12) h = 0;
    return [((h % 24) + 24) % 24, Math.max(0, Math.min(59, m))];
  }

  // "HH:MM"
  const hhmm = s.match(/^(\d{1,2}):(\d{2})$/);
  if (hhmm) {
    const h = parseInt(hhmm[1], 10);
    const m = parseInt(hhmm[2], 10);
    if (isFinite(h) && isFinite(m)) {
      return [((h % 24) + 24) % 24, Math.max(0, Math.min(59, m))];
    }
  }

  return [9, 0];
}

// Helper to always emit "HH:MM"
const fmtHHMM = (input) => {
  const [h, m] = hhmmParts(input);
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
};

// Build a normalized dictionary from the Sheet
const cfgRaw = {};
for (const [k, v] of pairs) {
  const lk = String(k).trim().toLowerCase();
  let val = v;

  // Normalize booleans
  if (/^(true|false)$/i.test(String(v))) {
    val = String(v).toLowerCase() === 'true';
  } else if (!isNaN(Number(v)) && v !== '') {
    // Numeric values become numbers (so times like "0.375" are numeric)
    val = Number(v);
  } else {
    val = String(v);
  }
  cfgRaw[lk] = val;
}

function parsePercent(p) {
  const n = parseFloat(String(p ?? '').replace('%', '').trim());
  return isFinite(n) ? n / 100 : 0;
}

// Pull hours (accept multiple header variants); format to "HH:MM"
const HOURS_OPEN_RAW  = cfgRaw['start_local_time'] ?? cfgRaw['hours_open']  ?? '12:30';
const HOURS_CLOSE_RAW = cfgRaw['end_local_time']   ?? cfgRaw['hours_close'] ?? '19:30';
const HOURS_OPEN_STR  = fmtHHMM(HOURS_OPEN_RAW);
const HOURS_CLOSE_STR = fmtHHMM(HOURS_CLOSE_RAW);

// Tax rate: prefer decimal in tax_rate; else parse state_rate_percent
let TAX_RATE = 0;
if (typeof cfgRaw['tax_rate'] === 'number' && isFinite(cfgRaw['tax_rate'])) {
  TAX_RATE = cfgRaw['tax_rate'];
} else {
  TAX_RATE = parsePercent(cfgRaw['state_rate_percent']);
}

// Compose final config
const out = {
  config: {
    timezone: cfgRaw['timezone'] || 'America/Chicago',
    hours_open: HOURS_OPEN_STR,         // always "HH:MM"
    hours_close: HOURS_CLOSE_STR,       // always "HH:MM"
    tax_rate: TAX_RATE,                 // decimal (e.g., 0.065)
    square_access_token: cfgRaw['square_access_token'] || '',
    square_location_id: cfgRaw['square_location_id'] || '',
    notify_email: cfgRaw['notify_email'] || cfgRaw['from_email'] || 'noreply@utopiadeli.local',
    send_email: cfgRaw['send_email'] === true || String(cfgRaw['send_email'] || '').toLowerCase() === 'true',
    send_sms:   cfgRaw['send_sms']   === true || String(cfgRaw['send_sms']   || '').toLowerCase() === 'true',
    sheet_id: cfgRaw['sheet_id'] || ''
  }
};

return [{ json: out }];

/**
 * Input:
 *  - $json.window.open_local or $json.config.hours_open (string) e.g. "12:30 PM", "12:30", "19:30", 0.5 (Excel fraction) etc.
 *  - $json.window.close_local or $json.config.hours_close (string)
 * Behavior:
 *  - Converts strings to minutes since midnight (America/Chicago)
 *  - Closed on Sundays (dow=0)
 *  - Returns { isOpen: boolean, window: { open_local, close_local, dow } }
 */

// ---------- helpers ----------
function chiNow() {
  const f = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Chicago', hourCycle: 'h23',
    weekday: 'short', hour: '2-digit', minute: '2-digit'
  });
  const p = Object.fromEntries(f.formatToParts(new Date()).map(t => [t.type, t.value]));
  const w2i = { Sun:0, Mon:1, Tue:2, Wed:3, Thu:4, Fri:5, Sat:6 };
  return { h: +p.hour, m: +p.minute, dow: w2i[p.weekday] };
}

function toHHMM(input) {
  // Accept: "12:30 PM", "12:30PM", "12:30", "19:30", 0.5 (Excel fraction), 9.5 (decimal hours)
  if (input == null) return { h: 12, m: 30 }; // default open
  let s = String(input).trim();

  // numeric (fraction of day or decimal hours)
  if (!isNaN(Number(s))) {
    const n = Number(s);
    if (n >= 0 && n < 1) { // Excel fraction of day
      const total = Math.round(n * 24 * 60);
      return { h: Math.floor(total/60) % 24, m: total % 60 };
    }
    if (n >= 1 && n < 24) { // decimal hours (e.g., 9.5)
      const h = Math.floor(n);
      const m = Math.round((n - h) * 60);
      return { h: (h % 24 + 24) % 24, m: Math.max(0, Math.min(59, m)) };
    }
  }

  // strip spaces for AM/PM parsing
  const noSpace = s.replace(/\s+/g,'');
  const ampm = noSpace.match(/^(\d{1,2})(?::?(\d{2}))?(am|pm)$/i);
  if (ampm) {
    let h = parseInt(ampm[1],10);
    const m = parseInt(ampm[2] ?? '0',10);
    const mer = ampm[3].toLowerCase();
    if (mer === 'pm' && h < 12) h += 12;
    if (mer === 'am' && h === 12) h = 0;
    return { h: (h % 24 + 24) % 24, m: Math.max(0, Math.min(59, m)) };
  }

  // HH:MM 24h
  const hhmm = s.match(/^(\d{1,2}):(\d{2})$/);
  if (hhmm) {
    const h = parseInt(hhmm[1],10);
    const m = parseInt(hhmm[2],10);
    return { h: (h % 24 + 24) % 24, m: Math.max(0, Math.min(59, m)) };
  }

  // last resort default
  return { h: 12, m: 30 };
}

function toMin(h, m) { return h*60 + m; }

// ---------- choose your source fields ----------
const openStr  = $json.window?.open_local  ?? $json.config?.hours_open  ?? '12:30 PM';
const closeStr = $json.window?.close_local ?? $json.config?.hours_close ?? '7:30 PM';

// parse times
const o = toHHMM(openStr);
const c = toHHMM(closeStr);

// current local time in Chicago
const now = chiNow();
const nowMin   = toMin(now.h, now.m);
const openMin  = toMin(o.h, o.m);
const closeMin = toMin(c.h, c.m);

// Open Mon–Fri only (Sun closed)
const isOpenDay  = now.dow >= 1 && now.dow <= 5;
const isOpenTime = nowMin >= openMin && nowMin <= closeMin;

return [{
  json: {
    isOpen: isOpenDay && isOpenTime,
    window: { open_local: `${String(o.h).padStart(2,'0')}:${String(o.m).padStart(2,'0')}`,
              close_local:`${String(c.h).padStart(2,'0')}:${String(c.m).padStart(2,'0')}`,
              dow: now.dow }
  }
}];

