  --opacity-placeholder: 0.6;

  /* Logo */
  --brand-logo-url: url('https://drive.google.com/uc?export=view&id=1EoM45ce5tUTsZoNdGljYVtjLNQA4XTVI');
  --brand-logo-height: 36px;
  --brand-logo-padding: 8px 0 16px 0;

  /* Elevation */
  --elev-1: 0 4px 16px rgba(17, 24, 39, 0.06); /* light */
  --elev-1-dark: 0 10px 24px rgba(0,0,0,0.35);  /* dark */
}

/* -----------------------------------------
   1) LIGHT THEME TOKENS (default)
   ----------------------------------------- */
:root,
:root[data-theme="light"] {
  --color-background: #FBFCFE;     /* page canvas */
  --color-card-bg: #FFFFFF;        /* card surface */
  --color-card-border: #E5E7EB;    /* outlines/dividers */
  --color-card-shadow: rgba(17,24,39,0.06);

  --color-header: var(--ud-primary);
  --color-header-subtext: #6B7280;

  --color-html-text: #1F2937;      /* darker for body copy */
  --color-label: #374151;
  --color-html-link: var(--ud-accent);

  --color-input-bg: #FFFFFF;
  --color-input-border: #D1D5DB;
  --color-input-text: #111827;     /* deep gray for readability */
  --color-input-placeholder: rgba(55,65,81,0.6);
  --color-focus-border: var(--ud-secondary);
  --focus-ring: 0 0 0 3px rgba(117, 70, 129, 0.18);

  --color-submit-btn-bg: var(--ud-accent);
  --color-submit-btn-text: #FFFFFF;
  --color-secondary-btn-bg: #F3F4F6;
  --color-secondary-btn-text: #1F2937;

  --color-test-notice-text: #6B3506;            /* readable on soft gold */
  --color-test-notice-bg: #FFF8EE;
  --color-test-notice-border: #F3D6A7;

  --color-error: #B91C1C; /* slightly darker than #EA1F30 for contrast */
  --color-required: var(--ud-accent);
}

/* -----------------------------------------
   2) DARK THEME TOKENS (auto + manual)
   ----------------------------------------- */
@media (prefers-color-scheme: dark) {
  :root:not([data-theme="light"]):not([data-theme="hc"]) {
    --color-background: #0F0F12;
    --color-card-bg: #111217;
    --color-card-border: #1F2430;
    --color-card-shadow: rgba(0,0,0,0.4);

    --color-header: #F2E8F0;            /* plum on dark (tint) */
    --color-header-subtext: #A9AFB8;

    --color-html-text: #E6E7EB;
    --color-label: #D3D5DB;
    --color-html-link: #E97B8A;         /* rose tint for dark */

    --color-input-bg: #0F1116;          /* dark field to spare eyes */
    --color-input-border: #2A2F3A;
    --color-input-text: #E6E7EB;        /* ✅ readable in dark fields */
    --color-input-placeholder: rgba(230,231,235,0.55);
    --color-focus-border: #B692C6;      /* violet tint */
    --focus-ring: 0 0 0 3px rgba(182,146,198,0.28);

    --color-submit-btn-bg: #C84B5D;     /* brighter rose for contrast on dark */
    --color-submit-btn-text: #0D0E12;
    --color-secondary-btn-bg: #1D2430;
    --color-secondary-btn-text: #E6E7EB;

    --color-test-notice-text: #F0C98B;  /* gold tint readable on dark */
    --color-test-notice-bg: #201A12;
    --color-test-notice-border: #3A2B18;

    --color-error: #F97066; /* warm error that passes on dark */
    --color-required: #FF9CA8;

    /* Elevation */
    --elev-1: var(--elev-1-dark);
  }
}

/* Manual dark override */
:root[data-theme="dark"] {
  /* Same as media query block above to force dark regardless of OS */
  --color-background: #0F0F12;
  --color-card-bg: #111217;
  --color-card-border: #1F2430;
  --color-card-shadow: rgba(0,0,0,0.4);

  --color-header: #F2E8F0;
  --color-header-subtext: #A9AFB8;

  --color-html-text: #E6E7EB;
  --color-label: #D3D5DB;
  --color-html-link: #E97B8A;

  --color-input-bg: #0F1116;
  --color-input-border: #2A2F3A;
  --color-input-text: #E6E7EB;          /* ✅ fixed */
  --color-input-placeholder: rgba(230,231,235,0.55);
  --color-focus-border: #B692C6;
  --focus-ring: 0 0 0 3px rgba(182,146,198,0.28);

  --color-submit-btn-bg: #C84B5D;
  --color-submit-btn-text: #0D0E12;
  --color-secondary-btn-bg: #1D2430;
  --color-secondary-btn-text: #E6E7EB;

  --color-test-notice-text: #F0C98B;
  --color-test-notice-bg: #201A12;
  --color-test-notice-border: #3A2B18;

  --color-error: #F97066;
  --color-required: #FF9CA8;

  --elev-1: var(--elev-1-dark);
}

/* -----------------------------------------
   3) Optional High-Contrast Theme
   ----------------------------------------- */
:root[data-theme="hc"] {
  --color-background: #0B0B0D;
  --color-card-bg: #0F0F12;
  --color-card-border: #323743;

  --color-header: #FFFFFF;
  --color-header-subtext: #CBD2D9;

  --color-html-text: #FFFFFF;
  --color-label: #FFFFFF;
  --color-html-link: #FF89A0;

  --color-input-bg: #0B0C10;
  --color-input-border: #4A5160;
  --color-input-text: #FFFFFF;
  --color-input-placeholder: rgba(255,255,255,0.6);
  --color-focus-border: #FFD166;
  --focus-ring: 0 0 0 3px rgba(255,209,102,0.45);

  --color-submit-btn-bg: #FF5C74;
  --color-submit-btn-text: #0D0E12;
  --color-secondary-btn-bg: #1C2230;
  --color-secondary-btn-text: #FFFFFF;

  --color-test-notice-text: #FFD166;
  --color-test-notice-bg: #1A1208;
  --color-test-notice-border: #6B4E1B;

  --color-error: #FF6B6B;
  --color-required: #FF9CA8;

  --elev-1: var(--elev-1-dark);
}

/* -----------------------------------------
   4) Structure & Components (shared)
   ----------------------------------------- */
.ud-container {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: var(--padding-container-top) 16px 32px;
  font-family: var(--font-family);
  color: var(--color-html-text);
  background: var(--color-background);
}

.ud-card {
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: var(--card-border-radius);
  padding: var(--card-padding);
  box-shadow: var(--elev-1);
  margin-bottom: var(--card-margin-bottom);
}

.ud-header {
  display: block;
  padding: var(--brand-logo-padding);
  border-bottom: 1px solid var(--color-card-border);
  color: var(--color-header);
  position: relative;
  min-height: calc(var(--brand-logo-height) + 16px);
  background-image: var(--brand-logo-url);
  background-repeat: no-repeat;
  background-position: left center;
  background-size: auto var(--brand-logo-height);
  padding-left: calc(var(--brand-logo-height) + 16px);
}
.ud-header h1 {
  margin: 0;
  font-size: var(--font-size-header);
  font-weight: var(--font-weight-bold);
  color: var(--color-header);
}
.ud-header .subtitle {
  margin-top: 4px;
  font-size: var(--font-size-subheader);
  color: var(--color-header-subtext);
}

/* Forms */
.ud-form-group { margin-top: 14px; }
.ud-label {
  display: inline-block;
  margin-bottom: 6px;
  font-size: var(--font-size-label);
  color: var(--color-label);
}

.ud-input,
.ud-select,
.ud-textarea {
  width: 100%;
  border: 1px solid var(--color-input-border);
  border-radius: var(--border-radius-input);
  padding: var(--padding-form-input);
  font-size: var(--font-size-input);
  color: var(--color-input-text);
  background: var(--color-input-bg);
  outline: none;
  transition: border-color 120ms ease, box-shadow 120ms ease, background-color 120ms ease, color 120ms ease;
}
.ud-input::placeholder,
.ud-textarea::placeholder {
  color: var(--color-input-placeholder);
  opacity: 1; /* we control via color token */
}
.ud-input:focus,
.ud-select:focus,
.ud-textarea:focus {
  border-color: var(--color-focus-border);
  box-shadow: var(--focus-ring);
}

.ud-checkrow {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 10px;
  font-size: var(--font-size-body);
  color: var(--color-html-text);
}
.ud-checkbox,
.ud-radio {
  width: var(--checkbox-size);
  height: var(--checkbox-size);
  accent-color: var(--ud-accent); /* native color for inputs */
}

/* Help, errors, required */
.ud-help {
  font-size: var(--font-size-body);
  color: var(--color-header-subtext);
  margin-top: 6px;
}
.ud-error {
  font-size: var(--font-size-error);
  color: var(--color-error);
  margin-top: 6px;
}
.ud-required { color: var(--color-required); }

/* Buttons */
.ud-actions {
  margin-top: 18px;
  display: flex;
  gap: 12px;
}
.ud-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: var(--submit-btn-height);
  padding: 0 16px;
  border-radius: 8px;
  border: none;
  font-weight: var(--font-weight-bold);
  cursor: pointer;
  transition: background-color 120ms ease, transform 50ms ease, color 120ms ease, box-shadow 120ms ease;
}
.ud-btn-primary {
  background: var(--color-submit-btn-bg);
  color: var(--color-submit-btn-text);
}
.ud-btn-primary:hover { filter: brightness(0.95); }
.ud-btn-primary:active { transform: translateY(1px); }
.ud-btn-primary:focus-visible { box-shadow: var(--focus-ring); outline: none; }

.ud-btn-secondary {
  background: var(--color-secondary-btn-bg);
  color: var(--color-secondary-btn-text);
}
.ud-btn-secondary:hover { filter: brightness(1.05); }
.ud-btn-secondary:active { transform: translateY(1px); }
.ud-btn-secondary:focus-visible { box-shadow: var(--focus-ring); outline: none; }

/* Links */
.ud-link {
  color: var(--color-html-link);
  text-decoration: underline;
}
.ud-link:hover { filter: brightness(0.95); }

/* Notices */
.ud-notice {
  margin-top: 14px;
  padding: var(--padding-test-notice-vertical) var(--padding-test-notice-horizontal);
  border: 1px solid var(--color-test-notice-border);
  background: var(--color-test-notice-bg);
  color: var(--color-test-notice-text);
  border-radius: 6px;
}

/* Responsive nicety */
@media (max-width: 480px) {
  .ud-container { padding: 16px; }
  .ud-header { padding-left: calc(var(--brand-logo-height) + 12px); }
}

/* Utility: force theme (optional)
   html[data-theme="dark"] .ud-container { ... }  // already handled via tokens
*/

parameters.jsCode:
let input = $json;

/**
 * Cart init
 */
let cart = input.cart || { items: [], subtotal_cents: 0 };

/**
 * ✅ Defensive base price handling
 */
let rawBasePrice =
  input.BasePrice ??
  input.BasaePrice ??   // typo fallback
  input.base_price ??
  0;

let basePriceCents = Math.round(Number(rawBasePrice) * 100);
if (!isFinite(basePriceCents)) basePriceCents = 0;

/**
 * ✅ ALL entrée modifier groups
 */
let modifierFields = [
  "Protein • Select 1",
  "Add Ons (Optional) • Select up to 1",
  "Extras • Select up to 3",
  "Combo (Optional) • Select up to 1",
  "Extra Sauce (Optional) • Select up to 6",
  "Take Off • Select up to 4",
  "No Ranch (Optional) • Select up to 1"
];

/**
 * Build entrée modifiers
 */
let modifiers = modifierFields
  .map(f => input[f])
  .filter(Boolean)
  .flatMap(v => Array.isArray(v) ? v : [v])
  .map(label => {
    let idMatch = label.match(/^\[([^\]]+)\]/);
    if (!idMatch) return null;

    let priceMatch = label.match(/\+\$?(\d+\.\d{2})/);
    let price_cents = priceMatch
      ? Math.round(parseFloat(priceMatch[1]) * 100)
      : 0;

    let cleanName = label
      .replace(/^\[[^\]]+\]\s*/, '')
      .replace(/\s+\+\$?.*$/, '');

    return {
      id: idMatch[1],
      name: price_cents === 0 ? `${cleanName} (no charge)` : cleanName,
      price_cents
    };
  })
  .filter(Boolean);

/**
 * Entrée totals
 */
let modifiersTotal = modifiers.reduce((s, m) => s + (m.price_cents || 0), 0);
let lineTotalCents = basePriceCents + modifiersTotal;

/**
 * ✅ Only create entrée item if entree exists
 */
let entreeItem = null;

if (input.ItemName && basePriceCents > 0) {
  entreeItem = {
    type: "entree",
    name: input.ItemName,
    quantity: Number(input.Quantity) || 1,
    price_cents: basePriceCents,
    line_total_cents: lineTotalCents,
    modifiers,
    notes: input.Notes || ""
  };
}

/**
 * ✅ UPSELL ITEMS
 */
let upsellItems = [];

/**
 * Fries, cookies, water
 */
[
  { item: "Plain/Loaded Fries ", qty: "Fry Quantity", addons: "Add Ons" },
  { item: "Sweets", qty: "Cookie Quantity" },
  { item: "Water 16oz", qty: "Water Quantity " }
].forEach(def => {
  let sel = input[def.item];
  let qty = Number(input[def.qty]) || 0;
  if (!sel || qty <= 0) return;

  let label = Array.isArray(sel) ? sel[0] : sel;
  let id = label.match(/^\[([^\]]+)\]/)?.[1];

  let priceMatch = label.match(/\+\$?(\d+\.\d{2})/);
  let price_cents = priceMatch
    ? Math.round(parseFloat(priceMatch[1]) * 100)
    : 0;

  let upsellModifiers = [];

  let extra = input[def.addons];
  if (extra) {
    let extras = Array.isArray(extra) ? extra : [extra];
    extras.forEach(e => {
      let m = e.match(/\+\$?(\d+\.\d{2})/);
      upsellModifiers.push({
        name: e.replace(/^\[[^\]]+\]\s*/, '').replace(/\s+\+\$?.*$/, ''),
        price_cents: m ? Math.round(parseFloat(m[1]) * 100) : 0
      });
    });
  }

  let modTotal = upsellModifiers.reduce((s, m) => s + m.price_cents, 0);

  upsellItems.push({
    type: "upsell",
    id,
    name: label.replace(/^\[[^\]]+\]\s*/, '').replace(/\s+\+\$?.*$/, ''),
    quantity: qty,
    price_cents,
    line_total_cents: (price_cents + modTotal) * qty,
    modifiers: upsellModifiers,
    notes: ""
  });
});

/**
 * ✅ Juice = flavor + size (fully safe)
 */
if (input["Cold Press Juice "] && Number(input["Juice Quantity"]) > 0) {
  let flavor = input["Cold Press Juice "]?.[0];
  let size = input["Juice Size"]?.[0];

  if (flavor) {
    let flavorName = flavor.replace(/^\[[^\]]+\]\s*/, '');

    let sizeMatch = size?.match(/\+\$?(\d+\.\d{2})/);
    let sizePrice = sizeMatch
      ? Math.round(parseFloat(sizeMatch[1]) * 100)
      : 0;

    let sizeName = size
      ? size.replace(/^\[[^\]]+\]\s*/, '').replace(/\s+\+\$?.*$/, '')
      : '';

    let displayName = sizeName
      ? `${flavorName} (${sizeName})`
      : flavorName;

    upsellItems.push({
      type: "upsell",
      id: flavor.match(/^\[([^\]]+)\]/)?.[1],
      name: displayName,
      quantity: Number(input["Juice Quantity"]),
      price_cents: sizePrice,
      line_total_cents: sizePrice * Number(input["Juice Quantity"]),
      modifiers: [],
      notes: input["Notes "] || ""
    });
  }
}

/**
 * ✅ Accumulate items (skip null entree)
 */
let items = [
  ...cart.items,
  ...(entreeItem ? [entreeItem] : []),
  ...upsellItems
];

/**
 * ✅ Safe subtotal
 */
let subtotal_cents = items.reduce((sum, item) => {
  let v = Number(item?.line_total_cents);
  return sum + (isFinite(v) ? v : 0);
}, 0);

/**
 * Output
 */
return [
  {
    json: {
      ...input,
      cart: {
        items,
        subtotal_cents
      }
    }
  }
];

/**
 * Build Square line_items from STATE_CART
 * Only runs when cart has items
 */

const cart =
  $node["STATE_CART"].json.cart &&
  Array.isArray($node["STATE_CART"].json.cart.items)
    ? $node["STATE_CART"].json.cart
    : { items: [] };

const line_items = cart.items.map(item => {
  const quantity = Math.max(Number(item.quantity) || 1, 1);
  const lineTotal = Number(item.line_total_cents) || 0;

  return {
    name: item.name || "Item",
    quantity: String(quantity),
    base_price_money: {
      amount: Math.round(lineTotal / quantity),
      currency: "USD"
    },
    note: [
      Array.isArray(item.modifiers) && item.modifiers.length
        ? item.modifiers
            .map(
              m =>
                `${m.name}${
                  m.price_cents
                    ? ` (+$${(m.price_cents / 100).toFixed(2)})`
                    : ""
                }`
            )
            .join(", ")
        : null,
      item.notes || null
    ]
      .filter(Boolean)
      .join(" | ")
  };
});

return [
  {
    json: {
      ...$json,
      square_line_items: line_items
    }
  }
];

/**
 * Build email HTML from cart
 * Fully loop-safe / navigation-safe
 */

// Normalize cart defensively
const cart =
  $json.cart && Array.isArray($json.cart.items)
    ? $json.cart
    : { items: [], subtotal_cents: 0 };

const customer = $json.customer || {};

const itemsHtml = cart.items
  .filter(item => item)
  .map(item => {
    const modifiers = Array.isArray(item.modifiers) ? item.modifiers : [];

    return `
      <tr>
        <td style="padding:8px 0;">
          <strong>${item.name || "Item"}</strong><br/>
          ${modifiers
            .map(
              m =>
                `<div style="font-size:12px;color:#555;">
                  ${m.name}${
                    m.price_cents
                      ? ` (+$${(m.price_cents / 100).toFixed(2)})`
                      : ""
                  }
                </div>`
            )
            .join("")}
          ${item.notes ? `<em>${item.notes}</em>` : ""}
        </td>
        <td align="right">
          $${((Number(item.line_total_cents) || 0) / 100).toFixed(2)}
        </td>
      </tr>
    `;
  })
  .join("");

return [{
  json: {
    ...$json,
    email_html_template: `
      <div style="font-family:Arial,sans-serif;max-width:600px;margin:auto;">
        <h2>We will begin preparing your order once we receive your payment.</h2>
        <p>Hi ${customer.name || "there"},</p>

        <p>Please complete your secure payment below:</p>

        <p style="text-align:center;">
          <a href="__PAYMENT_LINK__"
             style="background:#8C2F39;color:#fff;
             padding:14px 20px;border-radius:24px;
             text-decoration:none;font-weight:bold;">
            Complete Secure Payment
          </a>
        </p>

        <h3>Order Summary</h3>
        <table width="100%">
          ${itemsHtml}
          <tr>
            <td><strong>Subtotal</strong></td>
            <td align="right">
              <strong>
                $${((Number(cart.subtotal_cents) || 0) / 100).toFixed(2)}
              </strong>
            </td>
          </tr>
        </table>

        <p style="margin-top:24px;font-size:12px;color:#666;">
          © Utopia Deli · Pickup Order · Little Rock, AR
        </p>
      </div>
    `
  }
}];

/**
 * Inject payment link into email HTML
 * Final, execution-safe step
 */

const template = $json.email_html_template || null;
const link = $json.payment_link?.url || null;

if (!template) {
  throw new Error('Email HTML template is missing');
}

if (!link) {
  throw new Error('Payment link URL is missing');
}

return [{
  json: {
    ...$json,
    final_email_html: template.replace('__PAYMENT_LINK__', link)
  }
}];

const input = $json;

const cart = input.cart || { items: [], subtotal_cents: 0 };
const priceMap = input.modifier_price_map || {};

// Base price
const basePriceCents = Math.round(Number(input.BasePrice) * 100);

// Modifier fields from form
const modifierFields = [
  "Add Ons (Optional) • Select up to 1",
  "Combo (Optional) • Select up to 1",
  "Extra Sauce (Optional) • Select up to 6"
];

const modifiers = modifierFields
  .map(f => input[f])
  .filter(Boolean)
  .flatMap(v => Array.isArray(v) ? v : [v])
  .map(label => {
    const idMatch = label.match(/^\[([^\]]+)\]/);
    const modifierId = idMatch ? idMatch[1] : null;
    if (!modifierId) return null;

    // Prefer price map
    let price_cents = priceMap[modifierId];

    // Fallback to label price (restores previous behavior)
    if (price_cents == null) {
      const priceMatch = label.match(/\+\$(\d+\.\d{2})/);
      price_cents = priceMatch
        ? Math.round(parseFloat(priceMatch[1]) * 100)
        : 0;
    }

    return {
      id: modifierId,
      name: label
        .replace(/^\[[^\]]+\]\s*/, '')
        .replace(/\s+\+\$.*$/, ''),
      price_cents
    };
  })
  .filter(Boolean);

const modifiersTotal = modifiers.reduce((sum, m) => sum + m.price_cents, 0);
const lineTotalCents = basePriceCents + modifiersTotal;

const item = {
  type: (input.Category || 'unknown').toLowerCase(),
  name: input.ItemName,
  quantity: 1,

  // pricing truth
  base_price_cents: basePriceCents,
  line_total_cents: lineTotalCents,

  // display-only
  display_price_cents: basePriceCents,

  modifiers,
  notes: input.Notes || ""
};

const items = [...cart.items, item];
const subtotal_cents = items.reduce((sum, i) => sum + i.line_total_cents, 0);

return [
  {
    json: {
      ...input,
      cart: {
        items,
        subtotal_cents
      }
    }
  }
];

let cart = $json.cart;
let html = '<h2>Your Order</h2><ul>';

for (let item of cart.items) {
  html += '<li><strong>' + item.name + '</strong>';
  html += ' × ' + item.quantity;
  html += ' — $' + (item.price_cents / 100).toFixed(2);

  if (item.modifiers && item.modifiers.length) {
    html += '<ul>';
    for (let mod of item.modifiers) {
      html += '<li>' + mod.name;
      if (mod.price_cents > 0) {
        html += ' (+$' + (mod.price_cents / 100).toFixed(2) + ')';
      }
      html += '</li>';
    }
    html += '</ul>';
  }

  if (item.notes) {
    html += '<p><em>' + item.notes + '</em></p>';
  }

  html += '</li>';
}

html += '</ul>';
html += '<hr>';
html += '<p><strong>Subtotal:</strong> $' +
  (cart.subtotal_cents / 100).toFixed(2) +
'</p>';

return [{
  json: {
    ...$json,
    cart_summary_html: html
  }
}];

options.customCss:
/* =========================================================
   Utopia Deli — Accessible, Brand-Consistent Light/Dark CSS
   - Light & Dark tokens
   - OS auto + manual override via [data-theme]
   - Optimized form field readability
   - Safer focus outlines and button states
   ========================================================= */

/* ---------------------------
   0) Base (shared) tokens
   --------------------------- */
:root {
  /* Typography */
  --font-family: 'Open Sans', system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  --font-weight-normal: 400;
  --font-weight-bold: 600;
  --font-size-body: 12px;
  --font-size-label: 14px;
  --font-size-test-notice: 12px;
  --font-size-input: 14px;
  --font-size-header: 20px;
  --font-size-paragraph: 14px;
  --font-size-link: 12px;
  --font-size-error: 12px;
  --font-size-html-h1: 28px;
  --font-size-html-h2: 20px;
  --font-size-html-h3: 16px;
  --font-size-html-h4: 14px;
  --font-size-html-h5: 12px;
  --font-size-html-h6: 10px;
  --font-size-subheader: 14px;

  /* Brand */
  --ud-primary: #590B3F;   /* plum (headings, emphasis) */
  --ud-accent:  #AF3D4B;   /* rose (primary CTA) */
  --ud-secondary: #754681; /* violet (focus/interactive) */
  --ud-gold: #D59F5C;      /* gold (notices/highlights) */

  /* Component geometry */
  --border-radius-card: 8px;
  --border-radius-input: 6px;
  --border-radius-clear-btn: 50%;
  --card-border-radius: 8px;

  --padding-container-top: 24px;
  --padding-card: 24px;
  --padding-test-notice-vertical: 12px;
  --padding-test-notice-horizontal: 24px;
  --margin-bottom-card: 16px;
  --padding-form-input: 12px;
  --card-padding: 24px;
  --card-margin-bottom: 16px;

  --container-width: 448px;
  --submit-btn-height: 48px;
  --checkbox-size: 18px;

  --opacity-placeholder: 0.6;

  /* Logo */
  --brand-logo-url: url('https://drive.google.com/uc?export=view&id=1EoM45ce5tUTsZoNdGljYVtjLNQA4XTVI');
  --brand-logo-height: 36px;
  --brand-logo-padding: 8px 0 16px 0;

  /* Elevation */
  --elev-1: 0 4px 16px rgba(17, 24, 39, 0.06); /* light */
  --elev-1-dark: 0 10px 24px rgba(0,0,0,0.35);  /* dark */
}

/* -----------------------------------------
   1) LIGHT THEME TOKENS (default)
   ----------------------------------------- */
:root,
:root[data-theme="light"] {
  --color-background: #FBFCFE;     /* page canvas */
  --color-card-bg: #FFFFFF;        /* card surface */
  --color-card-border: #E5E7EB;    /* outlines/dividers */
  --color-card-shadow: rgba(17,24,39,0.06);

  --color-header: var(--ud-primary);
  --color-header-subtext: #6B7280;

  --color-html-text: #1F2937;      /* darker for body copy */
  --color-label: #374151;
  --color-html-link: var(--ud-accent);

  --color-input-bg: #FFFFFF;
  --color-input-border: #D1D5DB;
  --color-input-text: #111827;     /* deep gray for readability */
  --color-input-placeholder: rgba(55,65,81,0.6);
  --color-focus-border: var(--ud-secondary);
  --focus-ring: 0 0 0 3px rgba(117, 70, 129, 0.18);

  --color-submit-btn-bg: var(--ud-accent);
  --color-submit-btn-text: #FFFFFF;
  --color-secondary-btn-bg: #F3F4F6;
  --color-secondary-btn-text: #1F2937;

  --color-test-notice-text: #6B3506;            /* readable on soft gold */
  --color-test-notice-bg: #FFF8EE;
  --color-test-notice-border: #F3D6A7;

  --color-error: #B91C1C; /* slightly darker than #EA1F30 for contrast */
  --color-required: var(--ud-accent);
}

/* -----------------------------------------
   2) DARK THEME TOKENS (auto + manual)
   ----------------------------------------- */
@media (prefers-color-scheme: dark) {
  :root:not([data-theme="light"]):not([data-theme="hc"]) {
    --color-background: #0F0F12;
    --color-card-bg: #111217;
    --color-card-border: #1F2430;
    --color-card-shadow: rgba(0,0,0,0.4);

    --color-header: #F2E8F0;            /* plum on dark (tint) */
    --color-header-subtext: #A9AFB8;

    --color-html-text: #E6E7EB;
    --color-label: #D3D5DB;
    --color-html-link: #E97B8A;         /* rose tint for dark */

    --color-input-bg: #0F1116;          /* dark field to spare eyes */
    --color-input-border: #2A2F3A;
    --color-input-text: #E6E7EB;        /* ✅ readable in dark fields */
    --color-input-placeholder: rgba(230,231,235,0.55);
    --color-focus-border: #B692C6;      /* violet tint */
    --focus-ring: 0 0 0 3px rgba(182,146,198,0.28);

    --color-submit-btn-bg: #C84B5D;     /* brighter rose for contrast on dark */
    --color-submit-btn-text: #0D0E12;
    --color-secondary-btn-bg: #1D2430;
    --color-secondary-btn-text: #E6E7EB;

    --color-test-notice-text: #F0C98B;  /* gold tint readable on dark */
    --color-test-notice-bg: #201A12;
    --color-test-notice-border: #3A2B18;

    --color-error: #F97066; /* warm error that passes on dark */
    --color-required: #FF9CA8;

    /* Elevation */
    --elev-1: var(--elev-1-dark);
  }
}

/* Manual dark override */
:root[data-theme="dark"] {
  /* Same as media query block above to force dark regardless of OS */
  --color-background: #0F0F12;
  --color-card-bg: #111217;
  --color-card-border: #1F2430;
  --color-card-shadow: rgba(0,0,0,0.4);

  --color-header: #F2E8F0;
  --color-header-subtext: #A9AFB8;

  --color-html-text: #E6E7EB;
  --color-label: #D3D5DB;
  --color-html-link: #E97B8A;

  --color-input-bg: #0F1116;
  --color-input-border: #2A2F3A;
  --color-input-text: #E6E7EB;          /* ✅ fixed */
  --color-input-placeholder: rgba(230,231,235,0.55);
  --color-focus-border: #B692C6;
  --focus-ring: 0 0 0 3px rgba(182,146,198,0.28);

  --color-submit-btn-bg: #C84B5D;
  --color-submit-btn-text: #0D0E12;
  --color-secondary-btn-bg: #1D2430;
  --color-secondary-btn-text: #E6E7EB;

  --color-test-notice-text: #F0C98B;
  --color-test-notice-bg: #201A12;
  --color-test-notice-border: #3A2B18;

  --color-error: #F97066;
  --color-required: #FF9CA8;

  --elev-1: var(--elev-1-dark);
}

/* -----------------------------------------
   3) Optional High-Contrast Theme
   ----------------------------------------- */
:root[data-theme="hc"] {
  --color-background: #0B0B0D;
  --color-card-bg: #0F0F12;
  --color-card-border: #323743;

  --color-header: #FFFFFF;
  --color-header-subtext: #CBD2D9;

  --color-html-text: #FFFFFF;
  --color-label: #FFFFFF;
  --color-html-link: #FF89A0;

  --color-input-bg: #0B0C10;
  --color-input-border: #4A5160;
  --color-input-text: #FFFFFF;
  --color-input-placeholder: rgba(255,255,255,0.6);
  --color-focus-border: #FFD166;
  --focus-ring: 0 0 0 3px rgba(255,209,102,0.45);

  --color-submit-btn-bg: #FF5C74;
  --color-submit-btn-text: #0D0E12;
  --color-secondary-btn-bg: #1C2230;
  --color-secondary-btn-text: #FFFFFF;

  --color-test-notice-text: #FFD166;
  --color-test-notice-bg: #1A1208;
  --color-test-notice-border: #6B4E1B;

  --color-error: #FF6B6B;
  --color-required: #FF9CA8;

  --elev-1: var(--elev-1-dark);
}

/* -----------------------------------------
   4) Structure & Components (shared)
   ----------------------------------------- */
.ud-container {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: var(--padding-container-top) 16px 32px;
  font-family: var(--font-family);
  color: var(--color-html-text);
  background: var(--color-background);
}

.ud-card {
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: var(--card-border-radius);
  padding: var(--card-padding);
  box-shadow: var(--elev-1);
  margin-bottom: var(--card-margin-bottom);
}

.ud-header {
  display: block;
  padding: var(--brand-logo-padding);
  border-bottom: 1px solid var(--color-card-border);
  color: var(--color-header);
  position: relative;
  min-height: calc(var(--brand-logo-height) + 16px);
  background-image: var(--brand-logo-url);
  background-repeat: no-repeat;
  background-position: left center;
  background-size: auto var(--brand-logo-height);
  padding-left: calc(var(--brand-logo-height) + 16px);
}
.ud-header h1 {
  margin: 0;
  font-size: var(--font-size-header);
  font-weight: var(--font-weight-bold);
  color: var(--color-header);
}
.ud-header .subtitle {
  margin-top: 4px;
  font-size: var(--font-size-subheader);
  color: var(--color-header-subtext);
}

/* Forms */
.ud-form-group { margin-top: 14px; }
.ud-label {
  display: inline-block;
  margin-bottom: 6px;
  font-size: var(--font-size-label);
  color: var(--color-label);
}

.ud-input,
.ud-select,
.ud-textarea {
  width: 100%;
  border: 1px solid var(--color-input-border);
  border-radius: var(--border-radius-input);
  padding: var(--padding-form-input);
  font-size: var(--font-size-input);
  color: var(--color-input-text);
  background: var(--color-input-bg);
  outline: none;
  transition: border-color 120ms ease, box-shadow 120ms ease, background-color 120ms ease, color 120ms ease;
}
.ud-input::placeholder,
.ud-textarea::placeholder {
  color: var(--color-input-placeholder);
  opacity: 1; /* we control via color token */
}
.ud-input:focus,
.ud-select:focus,
.ud-textarea:focus {
  border-color: var(--color-focus-border);
  box-shadow: var(--focus-ring);
}

.ud-checkrow {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 10px;
  font-size: var(--font-size-body);
  color: var(--color-html-text);
}
.ud-checkbox,
.ud-radio {
  width: var(--checkbox-size);
  height: var(--checkbox-size);
  accent-color: var(--ud-accent); /* native color for inputs */
}

/* Help, errors, required */
.ud-help {
  font-size: var(--font-size-body);
  color: var(--color-header-subtext);
  margin-top: 6px;
}
.ud-error {
  font-size: var(--font-size-error);
  color: var(--color-error);
  margin-top: 6px;
}
.ud-required { color: var(--color-required); }

/* Buttons */
.ud-actions {
  margin-top: 18px;
  display: flex;
  gap: 12px;
}
.ud-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: var(--submit-btn-height);
  padding: 0 16px;
  border-radius: 8px;
  border: none;
  font-weight: var(--font-weight-bold);
  cursor: pointer;
  transition: background-color 120ms ease, transform 50ms ease, color 120ms ease, box-shadow 120ms ease;
}
.ud-btn-primary {
  background: var(--color-submit-btn-bg);
  color: var(--color-submit-btn-text);
}
.ud-btn-primary:hover { filter: brightness(0.95); }
.ud-btn-primary:active { transform: translateY(1px); }
.ud-btn-primary:focus-visible { box-shadow: var(--focus-ring); outline: none; }

.ud-btn-secondary {
  background: var(--color-secondary-btn-bg);
  color: var(--color-secondary-btn-text);
}
.ud-btn-secondary:hover { filter: brightness(1.05); }
.ud-btn-secondary:active { transform: translateY(1px); }
.ud-btn-secondary:focus-visible { box-shadow: var(--focus-ring); outline: none; }

/* Links */
.ud-link {
  color: var(--color-html-link);
  text-decoration: underline;
}
.ud-link:hover { filter: brightness(0.95); }

/* Notices */
.ud-notice {
  margin-top: 14px;
  padding: var(--padding-test-notice-vertical) var(--padding-test-notice-horizontal);
  border: 1px solid var(--color-test-notice-border);
  background: var(--color-test-notice-bg);
  color: var(--color-test-notice-text);
  border-radius: 6px;
}

/* Responsive nicety */
@media (max-width: 480px) {
  .ud-container { padding: 16px; }
  .ud-header { padding-left: calc(var(--brand-logo-height) + 12px); }
}

/* Utility: force theme (optional)
   html[data-theme="dark"] .ud-container { ... }  // already handled via tokens
*/

